def _normaliser(texte):
    """Casse, espaces, accents — pour une comparaison tolérante."""
    texte = (texte or "").strip().lower()
    texte = unicodedata.normalize("NFKD", texte)
    return "".join(c for c in texte if not unicodedata.combining(c))


def backfill_choix_est_correct(apps, schema_editor):
    """
    P2.2 : pour chaque Question de type qcm, marque est_correct=True sur
    l'UNIQUE Choix dont le texte (normalisé) correspond à bonne_reponse
    (normalisée). Questions à 0 ou plusieurs correspondances : signalées
    (logger.warning) et laissées inchangées — données déjà incohérentes,
    à traiter manuellement, pas de correction devinée ici.
    """
    Question = apps.get_model('evaluation', 'Question')

    nb_ok, nb_aucune, nb_plusieurs = 0, 0, 0
    for question in Question.objects.filter(type_question='qcm').prefetch_related('choix'):
        cible = _normaliser(question.bonne_reponse)
        correspondances = [c for c in question.choix.all() if _normaliser(c.texte) == cible]

        if len(correspondances) == 1:
            correspondances[0].est_correct = True
            correspondances[0].save(update_fields=['est_correct'])
            nb_ok += 1
        elif len(correspondances) == 0:
            nb_aucune += 1
            logger.warning(
                "P2.2 : aucun choix ne correspond à bonne_reponse pour Question id=%s "
                "(bonne_reponse=%r, choix=%r) — est_correct laissé à False partout, "
                "à corriger manuellement.",
                question.id, question.bonne_reponse, [c.texte for c in question.choix.all()],
            )
        else:
            nb_plusieurs += 1
            logger.warning(
                "P2.2 : plusieurs choix correspondent à bonne_reponse pour Question id=%s "
                "(bonne_reponse=%r, choix correspondants=%r) — est_correct laissé à False "
                "partout, ambiguïté à corriger manuellement.",
                question.id, question.bonne_reponse, [c.texte for c in correspondances],
            )

    logger.info(
        "P2.2 : backfill Choix.est_correct — %s questions résolues, %s sans correspondance, "
        "%s avec correspondances multiples (voir warnings ci-dessus).",
        nb_ok, nb_aucune, nb_plusieurs,
    )


def numeroter_choixreponse_ordre(apps, schema_editor):
    """P2.2 : numérote les ChoixReponse existants par id, par question."""
    QuestionDevoir = apps.get_model('evaluation', 'QuestionDevoir')

    nb = 0
    for question in QuestionDevoir.objects.prefetch_related('choix'):
        for i, choix in enumerate(question.choix.order_by('id'), start=1):
            choix.ordre = i
            choix.save(update_fields=['ordre'])
            nb += 1

    logger.info("P2.2 : %s ChoixReponse numérotés (ordre par id, par question).", nb)


